  1	import * as React from 'react';
  2	import { NodeModel } from '@odf/shared/models';
  3	import { getName, getUID } from '@odf/shared/selectors';
  4	import { TopologyDataContext } from '@odf/shared/topology';
  5	import { ResourceIcon } from '@openshift-console/dynamic-plugin-sdk';
  6	import {
  7	  Button,
  8	  ButtonVariant,
  9	  MenuToggle,
 10	  MenuToggleElement,
 11	  Select,
 12	  SelectList,
 13	  SelectOption,
 14	} from '@patternfly/react-core';
 15	import { AngleRightIcon } from '@patternfly/react-icons';
 16	import { useVisualizationController } from '@patternfly/react-topology';
 17	import { STEP_INTO_EVENT, STEP_TO_CLUSTER } from '../constants';
 18	import './TopologyNavigation.scss';
 19	
 20	const TopologyNavigationItem: React.FC = ({ children }) => {
 21	  return <div className="odf-topology-nav__item">{children}</div>;
 22	};
 23	
 24	type TopologyNavigationBarProps = {
 25	  initialNode: string;
 26	  updateCurrentNode: (node: string) => void;
 27	};
 28	
 29	const TopologyNavigationBar: React.FC<TopologyNavigationBarProps> = ({
 30	  initialNode,
 31	  updateCurrentNode,
 32	}) => {
 33	  const [isOpen, setOpen] = React.useState<boolean>(false);
 34	  const [selected, setSelected] = React.useState<string>(initialNode);
 35	
 36	  const { nodes } = React.useContext(TopologyDataContext);
 37	  const controller = useVisualizationController();
 38	
 39	  const onSelect = React.useCallback(
 40	    (event) => {
 41	      const id = event.currentTarget.id;
 42	      setSelected(id);
 43	      updateCurrentNode(id);
 44	      controller.fireEvent(STEP_INTO_EVENT, { label: id });
 45	    },
 46	    [controller, updateCurrentNode]
 47	  );
 48	
 49	  const menuItems = React.useMemo(
 50	    () =>
 51	      nodes.map((node) => {
 52	        const uid = getUID(node);
 53	        const name = getName(node);
 54	        return (
 55	          <SelectOption isSelected={selected === name} key={uid} id={name}>
 56	            <ResourceIcon
 57	              groupVersionKind={{
 58	                group: NodeModel.apiGroup,
 59	                version: NodeModel.apiVersion,
 60	                kind: NodeModel.kind,
 61	              }}
 62	            />
 63	            {name}
 64	          </SelectOption>
 65	        );
 66	      }),
 67	    [nodes, selected]
 68	  );
 69	
 70	  const onStorageClusterClick = (e: React.MouseEvent<HTMLButtonElement>) => {
 71	    e.stopPropagation();
 72	    controller.fireEvent(STEP_TO_CLUSTER);
 73	  };
 74	
 75	  const onToggleClick = () => {
 76	    setOpen(!isOpen);
 77	  };
 78	
 79	  const toggle = (toggleRef: React.Ref<MenuToggleElement>) => (
 80	    <MenuToggle ref={toggleRef} onClick={onToggleClick} isExpanded={isOpen}>
 81	      {selected}
 82	    </MenuToggle>
 83	  );
 84	
 85	  return (
 86	    <TopologyNavigationBarGroup>
 87	      <TopologyNavigationItem>
 88	        <Button
 89	          variant={ButtonVariant.link}
 90	          isInline
 91	          className="odf-topology-nav__item-storage-cluster-link"
 92	          onClick={onStorageClusterClick}
 93	        >
 94	          StorageCluster
 95	        </Button>
 96	      </TopologyNavigationItem>
 97	      <TopologyNavigationItem>
 98	        <ResourceIcon
 99	          groupVersionKind={{
100	            group: NodeModel.apiGroup,
101	            version: NodeModel.apiVersion,
102	            kind: NodeModel.kind,
103	          }}
104	        />
105	        <Select
106	          id="node-menu"
107	          isOpen={isOpen}
108	          onOpenChange={(newOpenState) => setOpen(newOpenState)}
109	          onSelect={onSelect}
110	          selected={selected}
111	          toggle={toggle}
112	          shouldFocusToggleOnSelect
113	        >
114	          <SelectList>{menuItems}</SelectList>
115	        </Select>
116	      </TopologyNavigationItem>
117	    </TopologyNavigationBarGroup>
118	  );
119	};
120	
121	const TopologyNavigationBarGroup: React.FC = ({ children }) => {
122	  const childArray = React.Children.toArray(children);
123	  return (
124	    <div className="odf-topology-nav">
125	      {childArray.map((child, i) => {
126	        const isLast = i === childArray.length - 1;
127	        if (!isLast) {
128	          return (
129	            <>
130	              {child}
131	              <TopologyNavigationItem key={i}>
132	                <AngleRightIcon />
133	              </TopologyNavigationItem>
134	            </>
135	          );
136	        } else {
137	          return <>{child}</>;
138	        }
139	      })}
140	    </div>
141	  );
142	};
143	
144	export default TopologyNavigationBar;

